// A Promise represents a value that will arrive in the future
const promise = new Promise((resolve, reject) => {
  const success = true;
  if (success) {
    resolve('Data loaded!');    // Fulfilled
  } else {
    reject(new Error('Failed')); // Rejected
  }
});

// .then() / .catch() chain (older style)
promise
  .then((data) => console.log(data))     // 'Data loaded!'
  .catch((err) => console.error(err));   // Only runs if rejected

// async/await (modern, cleaner style)
async function fetchUsers() {
  try {
    const response = await fetch('/api/users');

    if (!response.ok) {
      throw new Error(`HTTP ${response.status}: ${response.statusText}`);
    }

    const users = await response.json();
    return users;
  } catch (error) {
    console.error('Failed to fetch users:', error.message);
    return []; // Return a fallback value
  }
}

// Running async operations in parallel
async function loadDashboard() {
  // Bad: sequential (slow) -- each waits for the previous one
  // const users = await fetchUsers();
  // const posts = await fetchPosts();
  // const stats = await fetchStats();

  // Good: parallel (fast) -- all three start at the same time
  const [users, posts, stats] = await Promise.all([
    fetchUsers(),
    fetchPosts(),
    fetchStats(),
  ]);

  return { users, posts, stats };
}

// Promise.allSettled: wait for all, even if some fail
async function loadWithPartialFailure() {
  const results = await Promise.allSettled([
    fetchUsers(),
    fetchPosts(),
  ]);

  results.forEach((result) => {
    if (result.status === 'fulfilled') {
      console.log('Success:', result.value);
    } else {
      console.error('Failed:', result.reason);
    }
  });
}
